head.script:
scwin.sLoUpperLobranCd = "";
scwin.updateYN = "";
scwin.insertYN = "0";
scwin.strDate = "";
scwin.vCurDate = "";

scwin.onpageload = async function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strDate = scwin.vCurDate + scwin.vCurDate;
    scwin.sLoUpperLobranCd = $c.ses.getLoUpperLobranCd ? $c.ses.getLoUpperLobranCd() : "";

    wrkStDt.setValue(scwin.strDate);
    lo_eqKndCd.setValue("CT");

    await $c.sbm.execute(sbm_joblevel);
    await $c.sbm.execute(sbm_trfAdptCd);

    bilgMchtCd.setFocus();
    $c.gus.cfDisableBtn(["btn_Init"]);
};

scwin.onUdcCompleted = function() {
    wrkStDt.setValue(scwin.strDate);
    lo_eqKndCd.setValue("CT");
    bilgMchtCd.setFocus();
};

scwin.dataSetDebug = function(dataList, isDebug) {
    if (isDebug == true) {
        let str = "[[[[" + dataList.id + "]]]]]\n";
        for (let dsRow = 0; dsRow < dataList.getRowCount(); dsRow++) {
            let colCount = dataList.getColumnCount();
            for (let dsCol = 0; dsCol < colCount; dsCol++) {
                let colId = dataList.getColumnID(dsCol);
                str += "[" + colId + "] " + dataList.getCellData(dsRow, colId) + ", ";
            }
            str += "\n\n";
        }
    }
};

scwin.f_createHeader2 = function() {
    // TODO: ds_empCross2 dynamic header copy from ds_empCross cross-tab text is not directly supported in WebSquare
    // Original: ds_empCross2.SetDataHeader(ds_empCross.Text);
    // In WebSquare, the cross-tab dataset structure is pre-defined in dataCollection.
    // If dynamic columns are needed, use $c.data.createDataList or manual column manipulation.
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_Reset();
};

scwin.btn_Init_onclick = function(e) {
    scwin.f_Save();
};

scwin.btn_Copy_onclick = function(e) {
    scwin.f_Copy();
};

scwin.btn_Upt_onclick = function(e) {
    scwin.f_Update();
};

scwin.btn_rowAdd_onclick = function(e) {
    scwin.NewAddRow();
};

scwin.btn_rowDel_onclick = function(e) {
    scwin.f_Delete();
};

scwin.btn_Cancel_onclick = function(e) {
    scwin.CancleRow();
};

scwin.excel_sample_onclick = function(e) {
    scwin.f_sampleDownload();
};

scwin.btn_xls_onclick = function(e) {
    scwin.f_upload();
};

scwin.f_Retrieve = async function() {
    let commonChecked = (commonChe.getValue() != "");
    if (commonChecked == false) {
        if (bilgMchtCd.getValue() == "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["화주코드"]);
            bilgMchtCd.setFocus();
            return;
        }
        if (bilgMcht.getValue() == "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["화주명"]);
            bilgMcht.setFocus();
            return;
        }
    }

    if (ctrtNo.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["계약서"]);
        bilgMchtCd.setFocus();
        return;
    }

    dma_retrieve.set("branCd", co_lc_logisticsBranch.getValue());
    dma_retrieve.set("ctrtNo", ctrtNo.getValue());
    dma_retrieve.set("copCo", copCoCd.getValue());
    dma_retrieve.set("dptDistrictCd", dptDistrictCd.getValue().trim());
    dma_retrieve.set("arvDistrictCd", arvDistrictCd.getValue().trim());
    dma_retrieve.set("commCd", commCd.getValue());
    dma_retrieve.set("adptDt", wrkStDt.getValue().trim() == "" ? scwin.strDate : wrkStDt.getValue().trim());
    dma_retrieve.set("eqKndCd", lo_eqKndCd.getValue());
    dma_retrieve.set("pchsAmt", lo_pchsAmt.getValue());

    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_Save = async function() {
    if (!ds_empSave.isUpdated()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    }

    let chkValid = await $c.gus.cfValidate([gr_emp]);
    if (!chkValid) {
        return;
    }

    let chk = await $c.gus.cfConfirmMsg(MSG_CM_CRM_001);
    if (chk == true) {
        scwin.insertYN = "0";

        dma_retrieve.set("branCd", co_lc_logisticsBranch.getValue());
        dma_retrieve.set("ctrtNo", ctrtNo.getValue());
        dma_retrieve.set("copCo", copCoCd.getValue());
        dma_retrieve.set("dptDistrictCd", dptDistrictCd.getValue().trim());
        dma_retrieve.set("arvDistrictCd", arvDistrictCd.getValue().trim());
        dma_retrieve.set("commCd", commCd.getValue());
        dma_retrieve.set("adptDt", wrkStDt.getValue().trim());
        dma_retrieve.set("eqKndCd", lo_eqKndCd.getValue());
        dma_retrieve.set("pchsAmt", lo_pchsAmt.getValue());

        for (let i = 0; i < ds_empSave.getRowCount(); i++) {
            if (ds_empSave.getCellData(i, "copCoClntNm").trim() == "" || ds_empSave.getCellData(i, "copCoClntNm") == null) {
                ds_empSave.setCellData(i, "copCoClntNo", "999999");
            }
        }
        for (let i = 0; i < ds_empCross2.getRowCount(); i++) {
            if (ds_empCross2.getCellData(i, "wrkStHh").length != 4) {
                await $c.win.alert("적용시간(From)을 확인해 주세요");
                ds_empCross2.setRowPosition(i);
                gr_emp.setFocusedCell(i, "wrkStHh");
                return;
            } else if (ds_empCross2.getCellData(i, "wrkEndHh").length != 4) {
                await $c.win.alert("적용시간(To)을 확인해 주세요");
                ds_empCross2.setRowPosition(i);
                gr_emp.setFocusedCell(i, "wrkEndHh");
                return;
            }
        }
        await $c.sbm.execute(sbm_saveEmp);
    }
};

scwin.f_Copy = async function() {
    let cnt = ds_empSave.getRowCount();

    if (ds_empSave.getCellData(0, "ctrtNo") == ctrtNo.getValue() && ds_empSave.getCellData(0, "trfClsCd") == lo_pchsAmt.getValue()) {
        await $c.gus.cfAlertMsg("같은 계약서의 같은요율은 복사할 수 없습니다.");
        return;
    }

    for (let i = 0; i < cnt; i++) {
        ds_empSave.setCellData(i, "ctrtNo", ctrtNo.getValue());
        ds_empSave.setCellData(i, "trfClsCd", lo_pchsAmt.getValue());
    }

    if (!ds_empSave.isUpdated()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["자료"]);
        return;
    }

    let chkValid = await $c.gus.cfValidate([gr_emp]);
    if (!chkValid) {
        return;
    }

    let chk = await $c.gus.cfConfirmMsg(MSG_CM_CRM_001);
    if (chk == true) {
        scwin.insertYN = "0";

        dma_retrieve.set("branCd", co_lc_logisticsBranch.getValue());
        dma_retrieve.set("ctrtNo", ctrtNo.getValue());
        dma_retrieve.set("copCo", copCoCd.getValue());
        dma_retrieve.set("dptDistrictCd", dptDistrictCd.getValue().trim());
        dma_retrieve.set("arvDistrictCd", arvDistrictCd.getValue().trim());
        dma_retrieve.set("commCd", commCd.getValue());
        dma_retrieve.set("adptDt", wrkStDt.getValue().trim());
        dma_retrieve.set("eqKndCd", lo_eqKndCd.getValue());
        dma_retrieve.set("pchsAmt", lo_pchsAmt.getValue());

        await $c.sbm.execute(sbm_saveEmp2);
    }
};

scwin.f_Delete = function() {
    let rowState = 0;
    let row = 0;
    let newRow = 0;
    let xkeycnt = 0;

    for (let i = ds_empCross2.getRowCount() - 1; i >= 0; i--) {
        rowState = ds_empCross2.getRowStatus(i);
        if (rowState == "U") {
            row = i;
            xkeycnt = Math.floor((ds_empCross2.getColumnCount() - 21) / 2);
            newRow = xkeycnt * (row + 1);

            ds_empCross2.removeRow(i);

            for (let j = newRow - 1; j >= newRow - xkeycnt; j--) {
                if (j >= 0 && j < ds_empSave.getRowCount()) {
                    ds_empSave.removeRow(j);
                }
            }
        }
    }

    $c.gus.cfDisableKey();
    $c.gus.cfDisableBtn(["btn_Upt"]);
    scwin.insertYN = "0";
};

scwin.f_openCommPopUpGrid = async function(disGubun, row, pClose) {
    let rtnList;
    let pCode = "";
    let pName = "";

    if (disGubun == "1") {
        let param = "";
        let ctrtNoVal = ctrtNo.getValue() == null ? "" : ctrtNo.getValue();
        let commonChecked = (commonChe.getValue() != "");
        if (commonChecked) {
            param = ",,WDE";
        } else {
            if (ctrtNoVal != "") {
                param = ",," + ctrtNoVal;
            } else {
                await $c.win.alert("계약서번호를 선택하세요");
                return;
            }
        }

        let parma1 = "";
        let param2 = ds_empCross2.getCellData(row, "dptDistrictNm");
        let pAllSearch = "T";
        udc_dptDistrict.ilCommonPopUp(function(rtnListCb) {
            $c.gus.cfSetGridReturnValue(rtnListCb, ds_empCross2, row, "dptDistrictCd", "dptDistrictNm");
        }, parma1, param2, pClose, null, null, null, null, param, null, null, null, null, null, pAllSearch, "출발지,출발지코드,출발지명", null);
        return false;
    } else if (disGubun == "2") {
        let param = "";
        let ctrtNoVal = ctrtNo.getValue() == null ? "" : ctrtNo.getValue();
        let commonChecked = (commonChe.getValue() != "");
        if (commonChecked) {
            param = ",,WDE";
        } else {
            if (ctrtNoVal != "") {
                param = ",," + ctrtNoVal;
            } else {
                await $c.win.alert("계약서번호를 선택하세요");
                return;
            }
        }

        let parma1 = "";
        let param2 = ds_empCross2.getCellData(row, "arvDistrictNm");
        let pAllSearch = "T";
        udc_arvDistrict.ilCommonPopUp(function(rtnListCb) {
            $c.gus.cfSetGridReturnValue(rtnListCb, ds_empCross2, row, "arvDistrictCd", "arvDistrictNm");
        }, parma1, param2, pClose, null, null, null, null, param, null, null, null, null, null, pAllSearch, "도착지,도착지코드,도착지명", null);
        return false;
    } else if (disGubun == "3") {
        let param = "2,4,,," + "";
        let parma1 = "";
        let param2 = ds_empCross2.getCellData(row, "comm");
        let pAllSearch = "F";

        udc_comm.ilCommonPopUp(function(rtnListCb) {
            $c.gus.cfSetGridReturnValue(rtnListCb, ds_empCross2, row, "commCd", "comm");
        }, parma1, param2, "T", "3", "품목／품명코드,품목／품명,구분", "120,170,70", "4,5,6,7,8,9,10", param, "440", "500", null, null, null, null, "품목／품명,품목／품명코드,품목／품명");
        return false;
    } else if (disGubun == "4") {
        let param1 = "";
        let param2 = ds_empSave.getCellData(ds_empSave.getRowPosition(), "copCoClntNm");
        udc_copCo.ilCommonPopUp(function(rtnListCb) {
            $c.gus.cfSetGridReturnValue(rtnListCb, ds_empCross2, row, "copCoClntNo", "copCoClntNm");
        }, param1, param2, "T", null, null, null, null, null, null, null, null, null, null, null, "협력업체,협력업체코드,협력업체명");
        return false;
    }
};

scwin.f_openPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    if (disGubun == "1") {
        udc_bilgMcht.ilCommonPopUp(async function(rtnList) {
            $c.gus.cfSetReturnValue(rtnList, bilgMchtCd, bilgMcht);

            if (rtnList != null) {
                dma_retrieve2.set("ctrtClntNo", rtnList[0]);
                dma_retrieve2.set("ctrtCheck", "0");
                dma_retrieve2.set("ctrtDtYn", 1);

                await $c.sbm.execute(sbm_retrieve2);
            }

            commonChe.setValue("");
            copCoCd.setValue("");

            ctrtNo.setDisabled(false);
            copCoCd.setDisabled(false);
        }, pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "화주,화주코드,화주명");
    } else if (disGubun == "2") {
        let param = "";
        let ctrtNoVal = ctrtNo.getValue() == null ? "" : ctrtNo.getValue();
        let commonChecked = (commonChe.getValue() != "");
        if (commonChecked) {
            param = ",,WDE";
        } else {
            if (ctrtNoVal != "") {
                param = ",," + ctrtNoVal;
            } else {
                await $c.win.alert("계약서번호를 선택하세요");
                return;
            }
        }

        udc_dptDistrict.ilCommonPopUp(function(rtnList) {
            $c.gus.cfSetReturnValue(rtnList, dptDistrictCd, dptDistrictNm);
        }, pCode, pName, pClose, null, null, null, null, param, null, null, null, null, null, pAllSearch, "출발지,출발지코드,출발지명");
    } else if (disGubun == "3") {
        let param = "";
        let ctrtNoVal = ctrtNo.getValue() == null ? "" : ctrtNo.getValue();
        let commonChecked = (commonChe.getValue() != "");
        if (commonChecked) {
            param = ",,WDE";
        } else {
            if (ctrtNoVal != "") {
                param = ",," + ctrtNoVal;
            } else {
                await $c.win.alert("계약서번호를 선택하세요");
                return;
            }
        }

        udc_arvDistrict.ilCommonPopUp(function(rtnList) {
            $c.gus.cfSetReturnValue(rtnList, arvDistrictCd, arvDistrictNm);
        }, pCode, pName, pClose, null, null, null, null, param, null, null, null, null, null, pAllSearch, "도착지,도착지코드,도착지명");
    } else if (disGubun == "4") {
        if (bilgMchtCd.getValue() == "") {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["화주코드"]);
            bilgMchtCd.setFocus();
            return;
        }
        if (bilgMcht.getValue() == "") {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["화주명"]);
            bilgMcht.setFocus();
            return;
        }

        let param = "2,4,,," + "";
        udc_comm.ilCommonPopUp(function(rtnList) {
            $c.gus.cfSetReturnValue(rtnList, commCd, comm);
        }, pCode, pName, pClose, "3", "품목／품명코드,품목／품명,구분", "120,170,70", "4,5,6,7,8,9,10", param, "440", "500", null, null, null, null, "품목／품명,품목／품명코드,품목／품명");
    } else {
        udc_copCo.ilCommonPopUp(function(rtnList) {
            $c.gus.cfSetReturnValue(rtnList, copCoCd, copCoNm);
        }, pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "협력업체,협력업체코드,협력업체명");
    }
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openPopUp(disGubun, pVal, "", "T", "T");
    } else {
        scwin.f_openPopUp(disGubun, "", pVal, "T", "T");
    }
};

scwin.NewAddRow = async function() {
    let empRow = 0;
    let row = ds_empCross2.getRowPosition();
    let xkeycnt = Math.floor((ds_empCross2.getColumnCount() - 21) / 2);

    let chkValid = await $c.gus.cfValidate([gr_emp]);
    if (!chkValid) {
        return;
    }

    ds_empCross2.insertRow(ds_empCross2.getRowCount());
    let newPos = ds_empCross2.getRowCount() - 1;

    ds_empCross2.setCellData(newPos, "odrKndCd", ds_empCross2.getCellData(row, "odrKndCd"));
    ds_empCross2.setCellData(newPos, "alloccarBran", ds_empCross2.getCellData(row, "alloccarBran"));
    ds_empCross2.setCellData(newPos, "copCoClntNo", ds_empCross2.getCellData(row, "copCoClntNo"));
    ds_empCross2.setCellData(newPos, "copCoClntNm", ds_empCross2.getCellData(row, "copCoClntNm"));
    ds_empCross2.setCellData(newPos, "ctrtNo", ds_empCross2.getCellData(row, "ctrtNo"));
    ds_empCross2.setCellData(newPos, "adptDt", ds_empCross2.getCellData(row, "adptDt"));
    ds_empCross2.setCellData(newPos, "dptDistrictNm", ds_empCross2.getCellData(row, "dptDistrictNm"));
    ds_empCross2.setCellData(newPos, "arvDistrictNm", ds_empCross2.getCellData(row, "arvDistrictNm"));
    ds_empCross2.setCellData(newPos, "comm", ds_empCross2.getCellData(row, "comm"));
    ds_empCross2.setCellData(newPos, "unitCd", ds_empCross2.getCellData(row, "unitCd"));
    ds_empCross2.setCellData(newPos, "eqKndCd", ds_empCross2.getCellData(row, "eqKndCd"));
    ds_empCross2.setCellData(newPos, "eqNrmCd", ds_empCross2.getCellData(row, "eqNrmCd"));
    ds_empCross2.setCellData(newPos, "eqNrmNm", ds_empCross2.getCellData(row, "eqNrmNm"));
    ds_empCross2.setCellData(newPos, "dptDistrictCd", ds_empCross2.getCellData(row, "dptDistrictCd"));
    ds_empCross2.setCellData(newPos, "arvDistrictCd", ds_empCross2.getCellData(row, "arvDistrictCd"));
    ds_empCross2.setCellData(newPos, "commCd", ds_empCross2.getCellData(row, "commCd"));
    ds_empCross2.setCellData(newPos, "expireDt", ds_empCross2.getCellData(row, "expireDt"));
    ds_empCross2.setCellData(newPos, "trfClsCd", ds_empCross2.getCellData(row, "trfClsCd"));
    ds_empCross2.setCellData(newPos, "trfAdptNm", ds_empCross2.getCellData(row, "trfAdptNm"));
    ds_empCross2.setCellData(newPos, "trfAdptCd", ds_empCross2.getCellData(row, "trfAdptCd"));
    ds_empCross2.setCellData(newPos, "wrkStHh", ds_empCross2.getCellData(row, "wrkStHh"));
    ds_empCross2.setCellData(newPos, "wrkEndHh", ds_empCross2.getCellData(row, "wrkEndHh"));

    for (let i = 1; i <= xkeycnt; i++) {
        ds_empCross2.setCellData(newPos, "pchsAmt_" + i, ds_empCross2.getCellData(row, "pchsAmt_" + i));
    }

    empRow = ds_empSave.getRowCount();

    for (let k = 0; k < xkeycnt; k++) {
        ds_empSave.insertRow(ds_empSave.getRowCount());
        let savePos = ds_empSave.getRowCount() - 1;

        ds_empSave.setCellData(savePos, "odrKndCd", ds_empCross2.getCellData(row, "odrKndCd"));
        ds_empSave.setCellData(savePos, "alloccarBran", ds_empCross2.getCellData(row, "alloccarBran"));
        ds_empSave.setCellData(savePos, "copCoClntNo", ds_empCross2.getCellData(row, "copCoClntNo"));
        ds_empSave.setCellData(savePos, "copCoClntNm", ds_empCross2.getCellData(row, "copCoClntNm"));
        ds_empSave.setCellData(savePos, "ctrtNo", ds_empCross2.getCellData(row, "ctrtNo"));
        ds_empSave.setCellData(savePos, "adptDt", ds_empCross2.getCellData(row, "adptDt"));
        ds_empSave.setCellData(savePos, "dptDistrictNm", ds_empCross2.getCellData(row, "dptDistrictNm"));
        ds_empSave.setCellData(savePos, "arvDistrictNm", ds_empCross2.getCellData(row, "arvDistrictNm"));
        ds_empSave.setCellData(savePos, "comm", ds_empCross2.getCellData(row, "comm"));
        ds_empSave.setCellData(savePos, "unitCd", ds_empCross2.getCellData(row, "unitCd"));
        ds_empSave.setCellData(savePos, "eqKndCd", ds_empSave.getCellData(k, "eqKndCd"));
        ds_empSave.setCellData(savePos, "eqNrmCd", ds_empSave.getCellData(k, "eqNrmCd"));
        ds_empSave.setCellData(savePos, "eqNrmNm", ds_empSave.getCellData(k, "eqNrmNm"));
        ds_empSave.setCellData(savePos, "dptDistrictCd", ds_empCross2.getCellData(row, "dptDistrictCd"));
        ds_empSave.setCellData(savePos, "arvDistrictCd", ds_empCross2.getCellData(row, "arvDistrictCd"));
        ds_empSave.setCellData(savePos, "commCd", ds_empCross2.getCellData(row, "commCd"));
        ds_empSave.setCellData(savePos, "expireDt", ds_empCross2.getCellData(row, "expireDt"));
        ds_empSave.setCellData(savePos, "trfClsCd", ds_empCross2.getCellData(row, "trfClsCd"));
        ds_empSave.setCellData(savePos, "trfAdptNm", ds_empCross2.getCellData(row, "trfAdptNm"));
        ds_empSave.setCellData(savePos, "trfAdptCd", ds_empCross2.getCellData(row, "trfAdptCd"));
        ds_empSave.setCellData(savePos, "wrkStHh", ds_empCross2.getCellData(row, "wrkStHh"));
        ds_empSave.setCellData(savePos, "wrkEndHh", ds_empCross2.getCellData(row, "wrkEndHh"));
        ds_empSave.setCellData(savePos, "pchsAmt", ds_empCross2.getCellData(row, "pchsAmt_" + (k + 1)));
    }

    gr_emp.setReadOnly("grid", false);
    gr_emp.setFocusedCell(newPos, "adptDt");

    $c.gus.cfDisableKey();
    $c.gus.cfDisableBtn(["btn_Upt"]);
    scwin.insertYN = "0";
};

scwin.CancleRow = function() {
    ds_empCross2.undoAll();
    ds_empSave.undoAll();
    $c.gus.cfDisableKey();
    $c.gus.cfDisableBtn(["btn_Upt"]);
    scwin.insertYN = "0";
};

scwin.f_Update = async function() {
