scwin.sortGridData = function(p_datasetNm, p_row, p_colId, p_datasetNm2) {
    let datasetObj = null;
    let datasetObj2 = null;

    datasetObj = WebSquare.util.getComponentById(p_datasetNm);
    datasetObj2 = WebSquare.util.getComponentById(p_datasetNm2);

    if (p_row == 0 && datasetObj2.getRowCount() > 0) {
        if (datasetObj2.getSortExpr && datasetObj2.getSortExpr().substring(0, 1) == "+") {
            datasetObj.sort(p_colId, "desc");
        } else {
            datasetObj.sort(p_colId, "asc");
        }
    }
};

scwin.cfCopyDataSet2 = function(oOriginDataList, oTargetDataList, features) {
    let copyHeader = true;
    let resetStatus = true;
    let rowFrom = 0;
    let rowCnt = oOriginDataList.getRowCount();

    if (features != null) {
        if (features.indexOf("copyHeader=no") >= 0) {
            copyHeader = false;
        }
        if (features.indexOf("resetStatus=no") >= 0) {
            resetStatus = false;
        }
        let rowFromMatch = features.match(/rowFrom=(\d+)/);
        if (rowFromMatch) {
            rowFrom = parseInt(rowFromMatch[1]) - 1;
        }
        let rowCntMatch = features.match(/rowCnt=(\d+)/);
        if (rowCntMatch) {
            rowCnt = parseInt(rowCntMatch[1]);
        }
    }

    oTargetDataList.removeAll();
    if (oOriginDataList.getRowCount() > 0) {
        for (let i = rowFrom; i < rowFrom + rowCnt && i < oOriginDataList.getRowCount(); i++) {
            oTargetDataList.insertRow(oTargetDataList.getRowCount());
            let newIdx = oTargetDataList.getRowCount() - 1;
            let colCount = oOriginDataList.getColumnCount();
            for (let c = 0; c < colCount; c++) {
                let colId = oOriginDataList.getColumnID(c);
                oTargetDataList.setCellData(newIdx, colId, oOriginDataList.getCellData(i, colId));
            }
        }
        if (resetStatus == true) {
            // TODO: resetStatus equivalent in WebSquare
        }
    }
};

