scwin.gr_emp_oneditend = function(rowIndex, columnIndex, columnId, oldValue, newValue) {
    let empRow = 0;
    let newRow = 0;
    let xkeycnt = Math.floor((ds_empCross2.getColumnCount() - 21) / 2);

    if (rowIndex >= 0 && ds_empCross2.getRowCount() > rowIndex) {
        switch (columnId) {
            case "dptDistrictNm":
                if (ds_empCross2.getCellData(rowIndex, columnId) != "" && ds_empCross2.getCellData(rowIndex, columnId) != oldValue) {
                    ds_empCross2.setCellData(rowIndex, "dptDistrictCd", "");
                    scwin.f_openCommPopUpGrid("1", rowIndex, "T");
                } else if (ds_empCross2.getCellData(rowIndex, columnId) == "") {
                    ds_empCross2.setCellData(rowIndex, "dptDistrictCd", "");
                    ds_empCross2.setCellData(rowIndex, "dptDistrictNm", "");
                }
                break;
            case "arvDistrictNm":
                if (ds_empCross2.getCellData(rowIndex, columnId) != "" && ds_empCross2.getCellData(rowIndex, columnId) != oldValue) {
                    ds_empCross2.setCellData(rowIndex, "arvDistrictCd", "");
                    scwin.f_openCommPopUpGrid("2", rowIndex, "T");
                } else if (ds_empCross2.getCellData(rowIndex, columnId) == "") {
                    ds_empCross2.setCellData(rowIndex, "arvDistrictCd", "");
                    ds_empCross2.setCellData(rowIndex, "arvDistrictNm", "");
                }
                break;
            case "comm":
                if (ds_empCross2.getCellData(rowIndex, columnId) != "" && ds_empCross2.getCellData(rowIndex, columnId) != oldValue) {
                    ds_empCross2.setCellData(rowIndex, "commCd", "");
                    scwin.f_openCommPopUpGrid("3", rowIndex, "T");
                } else if (ds_empCross2.getCellData(rowIndex, columnId) == "") {
                    ds_empCross2.setCellData(rowIndex, "commCd", "");
                    ds_empCross2.setCellData(rowIndex, "comm", "");
                }
                break;
            case "copCoClntNm":
                if (ds_empCross2.getCellData(rowIndex, columnId) != "" && ds_empCross2.getCellData(rowIndex, columnId) != oldValue) {
                    ds_empCross2.setCellData(rowIndex, "copCoClntNo", "");
                    scwin.f_openCommPopUpGrid("4", rowIndex, "T");
                } else if (ds_empCross2.getCellData(rowIndex, columnId) == "") {
                    ds_empCross2.setCellData(rowIndex, "copCoClntNo", "");
                    ds_empCross2.setCellData(rowIndex, "copCoClntNm", "");
                }
                break;
        }

        if (columnId.substring(0, 7) == "pchsAmt" && columnId.length > 7) {
            empRow = parseInt(columnId.substring(8)) + xkeycnt * rowIndex;
            if (empRow >= 0 && empRow < ds_empSave.getRowCount()) {
                ds_empSave.setCellData(empRow, "pchsAmt", ds_empCross2.getCellData(rowIndex, columnId));
            }
        }

        let rowStatus = ds_empCross2.getRowStatus(rowIndex);
        newRow = xkeycnt * rowIndex;

        if (rowStatus == "D") {
            if (columnId.substring(0, 7) == "pchsAmt" && columnId.length > 7) {
                empRow = parseInt(columnId.substring(8)) + xkeycnt * rowIndex;
                if (empRow >= 0 && empRow < ds_empSave.getRowCount()) {
                    ds_empSave.setCellData(empRow, "pchsAmt", ds_empCross2.getCellData(rowIndex, columnId));
                }
            } else {
                for (let j = 0; j < xkeycnt; j++) {
                    let idx = newRow + j;
                    if (idx < ds_empSave.getRowCount()) {
                        ds_empSave.setCellData(idx, "alloccarBran", ds_empCross2.getCellData(rowIndex, "alloccarBran"));
                        ds_empSave.setCellData(idx, "copCoClntNo", ds_empCross2.getCellData(rowIndex, "copCoClntNo"));
