                        ds_empSave.setCellData(idx, "trfAdptCd", ds_empCross2.getCellData(rowIndex, "trfAdptCd"));
                        ds_empSave.setCellData(idx, "wrkStHh", ds_empCross2.getCellData(rowIndex, "wrkStHh"));
                        ds_empSave.setCellData(idx, "wrkEndHh", ds_empCross2.getCellData(rowIndex, "wrkEndHh"));
                    }
                }
            }
        } else if (rowStatus == "C") {
            for (let j = 0; j < xkeycnt; j++) {
                let idx = newRow + j;
                if (idx < ds_empSave.getRowCount()) {
                    ds_empSave.setCellData(idx, "alloccarBran", ds_empCross2.getCellData(rowIndex, "alloccarBran"));
                    ds_empSave.setCellData(idx, "copCoClntNo", ds_empCross2.getCellData(rowIndex, "copCoClntNo"));
                    ds_empSave.setCellData(idx, "copCoClntNm", ds_empCross2.getCellData(rowIndex, "copCoClntNm"));
                    ds_empSave.setCellData(idx, "ctrtNo", ds_empCross2.getCellData(rowIndex, "ctrtNo"));
                    ds_empSave.setCellData(idx, "adptDt", ds_empCross2.getCellData(rowIndex, "adptDt"));
                    ds_empSave.setCellData(idx, "dptDistrictNm", ds_empCross2.getCellData(rowIndex, "dptDistrictNm"));
                    ds_empSave.setCellData(idx, "arvDistrictNm", ds_empCross2.getCellData(rowIndex, "arvDistrictNm"));
                    ds_empSave.setCellData(idx, "comm", ds_empCross2.getCellData(rowIndex, "comm"));
                    ds_empSave.setCellData(idx, "unitCd", ds_empCross2.getCellData(rowIndex, "unitCd"));
                    ds_empSave.setCellData(idx, "eqKndCd", ds_empCross2.getCellData(rowIndex, "eqKndCd"));
                    ds_empSave.setCellData(idx, "eqNrmCd", ds_empCross2.getCellData(rowIndex, "eqNrmCd"));
                    ds_empSave.setCellData(idx, "eqNrmNm", ds_empCross2.getCellData(rowIndex, "eqNrmNm"));
                    ds_empSave.setCellData(idx, "trfClsCd", ds_empCross2.getCellData(rowIndex, "trfClsCd"));
                    ds_empSave.setCellData(idx, "dptDistrictCd", ds_empCross2.getCellData(rowIndex, "dptDistrictCd"));
                    ds_empSave.setCellData(idx, "arvDistrictCd", ds_empCross2.getCellData(rowIndex, "arvDistrictCd"));
                    ds_empSave.setCellData(idx, "commCd", ds_empCross2.getCellData(rowIndex, "commCd"));
                    ds_empSave.setCellData(idx, "expireDt", ds_empCross2.getCellData(rowIndex, "expireDt"));
                    ds_empSave.setCellData(idx, "trfAdptNm", ds_empCross2.getCellData(rowIndex, "trfAdptNm"));
                    ds_empSave.setCellData(idx, "trfAdptCd", ds_empCross2.getCellData(rowIndex, "trfAdptCd"));
                    ds_empSave.setCellData(idx, "wrkStHh", ds_empCross2.getCellData(rowIndex, "wrkStHh"));
                    ds_empSave.setCellData(idx, "wrkEndHh", ds_empCross2.getCellData(rowIndex, "wrkEndHh"));
                }
            }
            if (columnId.substring(0, 7) == "pchsAmt" && columnId.length > 7) {
                empRow = parseInt(columnId.substring(8)) + xkeycnt * rowIndex;
                if (empRow >= 0 && empRow < ds_empSave.getRowCount()) {
                    ds_empSave.setCellData(empRow, "pchsAmt", ds_empCross2.getCellData(rowIndex, columnId));
                }
            }
        } else if (rowStatus == "U") {
        }
    }
};

scwin.gr_emp_oncloseup = function(rowIndex, columnIndex, columnId) {
    let newRow = 0;
    let xkeycnt = Math.floor((ds_empCross2.getColumnCount() - 21) / 2);

    newRow = xkeycnt * rowIndex;

    for (let j = 0; j < xkeycnt; j++) {
        let idx = newRow + j;
        if (idx < ds_empSave.getRowCount()) {
            ds_empSave.setCellData(idx, "unitCd", ds_empCross2.getCellData(rowIndex, "unitCd"));
            ds_empSave.setCellData(idx, "odrKndCd", ds_empCross2.getCellData(rowIndex, "odrKndCd"));
            ds_empSave.setCellData(idx, "trfAdptCd", ds_empCross2.getCellData(rowIndex, "trfAdptCd"));
        }
    }
};

scwin.sbm_retrieve_submitdone = async function(e) {
    let rowCnt = ds_emp.getRowCount();
    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002, [""]);
    }

    let xkeycnt = Math.floor((ds_empCross2.getColumnCount() - 21) / 2);

    totalRows.setValue(ds_empCross2.getRowCount());

    scwin.cfCopyDataSet2(ds_emp, ds_empCross2, "copyHeader=yes");

    gr_emp.setReadOnly("grid", true);

    if (ds_empCross2.getRowCount() > 0) {
        if (ds_empCross2.getCellData(0, "dptDistrictNm") == "" || ds_empCross2.getCellData(0, "arvDistrictNm") == "" || ds_empCross2.getCellData(0, "comm") == "" || ds_empCross2.getCellData(0, "unitCd") == "") {
            gr_emp.setReadOnly("grid", false);
            $c.gus.cfDisableKey();
            $c.gus.cfDisableBtn(["btn_Upt"]);
            scwin.insertYN = "1";
        } else {
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtn(["btn_Init"]);
            scwin.insertYN = "0";
        }
    }
};

